{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple project management API",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "dependencies": {
    "express": "^4.17.3"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}

const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Message is required');
  }
  try {
    const comment = await commentsService.createComment(req.params.taskId, message);
    res.json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await commentsService.getComments(req.params.taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let commentsStore = [];

const createComment = async (taskId, message) => {
  const commentId = randomUUID();
  const comment = { id: commentId, taskId, message };
  commentsStore.push(comment);
  return comment;
};

const getComments = async (taskId) => {
  return commentsStore.filter(comment => comment.taskId === taskId);
};

module.exports = { createComment, getComments };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'UserId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await membersService.getMembers(req.params.projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let membersStore = [];

const addMember = async (projectId, userId, role) => {
  const memberId = randomUUID();
  const member = { id: memberId, projectId, userId, role };
  membersStore.push(member);
  return member;
};

const getMembers = async (projectId) => {
  return membersStore.filter(member => member.projectId === projectId);
};

module.exports = { addMember, getMembers };

const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let projectsStore = [];

const createProject = async (name) => {
  const projectId = randomUUID();
  const project = { id: projectId, name };
  projectsStore.push(project);
  return project;
};

const getAllProjects = async () => {
  return projectsStore;
};

const getProjectById = async (projectId) => {
  return projectsStore.find(project => project.id === projectId);
};

module.exports = { createProject, getAllProjects, getProjectById };

const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    let tasks = await tasksService.getTasks(req.params.projectId);
    if (status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'done', 'pending' ].includes(status)) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const createTask = async (projectId, title) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'pending' };
  tasksStore.push(task);
  return task;
};

const getTasks = async (projectId) => {
  return tasksStore.filter(task => task.projectId === projectId);
};

const updateTaskStatus = async (taskId, status) => {
  const task = tasksStore.find(task => task.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getTasks, updateTaskStatus };
